     1→import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
     2→import { useBackHandler } from '../../services/useBackHandler';
     3→import { User } from 'firebase/auth';
     4→import { Capacitor } from '@capacitor/core';
     5→import { 
     6→  X, ArrowRight, Image as ImageIcon, Loader2, AlertTriangle, 
     7→  CheckCircle2, Trash2, Edit2, Package, Sparkles, MessageCircle,
     8→  Send, WifiOff, RefreshCw, Mic, MicOff
     9→} from 'lucide-react';
    10→import { GeminiService } from '../../services/gemini';
    11→import { ApiService } from '../../services/api';
    12→import { useUI } from '../../context/UIContext';
    13→import { useData } from '../../context/DataContext';
    14→import { AppSettings } from '../../types';
    15→import { haptic } from '../../utils/haptics';
    16→import { OfflineQueueService } from '../../services/offlineQueue';
    17→import { SyncQueueService } from '../../services/syncQueue';
    18→import { getIDForEntry } from '../../utils/idGenerator';
    19→import ManualEntryModal from '../modals/ManualEntryModal';
    20→
    21→interface Message {
    22→  id: string;
    23→  role: 'user' | 'assistant';
    24→  content: string;
    25→  data?: any[];
    26→  timestamp: Date;
    27→}
    28→
    29→interface CommandModalProps {
    30→  isOpen: boolean;
    31→  onClose: () => void;
    32→  user: User;
    33→  onSuccess?: () => void;
    34→  appSettings?: AppSettings;
    35→}
    36→
    37→const CommandModal: React.FC<CommandModalProps> = ({ isOpen, onClose, user, onSuccess, appSettings }) => {
    38→  const { showToast } = useUI();
    39→  const { useParties, useInventory, invalidateAll } = useData();
    40→
    41→  // Register with central back stack — Android back closes this modal
    42→  useBackHandler(onClose, isOpen, 10);
    43→  
    44→  // Use cached data from DataContext
    45→  const { data: parties } = useParties(user.uid);
    46→  const { data: inventory } = useInventory(user.uid);
    47→  
    48→  // Chat State
    49→  const [messages, setMessages] = useState<Message[]>([]);
    50→  const [input, setInput] = useState('');
    51→  const [file, setFile] = useState<File | null>(null);
    52→  const messagesEndRef = useRef<HTMLDivElement>(null);
    53→  
    54→  // Processing State — `aiLoading` is for the send/AI-processing path;
    55→  // `savingMsgIds` tracks which individual messages are mid-save so each
    56→  // "Save All" button shows its own spinner independently.
    57→  const [aiLoading, setAiLoading] = useState(false);
    58→  const [savingMsgIds, setSavingMsgIds] = useState<Set<string>>(new Set());
    59→  const [isOnline, setIsOnline] = useState(navigator.onLine);
    60→  const [pendingCount, setPendingCount] = useState(0);
    61→  
    62→  // Edit State
    63→  const [editData, setEditData] = useState<any>(null);
    64→  const [showEditModal, setShowEditModal] = useState(false);
    65→
    66→  // Voice recognition
    67→  // Web Speech API is unavailable inside Android/iOS WebView — only show mic on web.
    68→  const voiceSupported = useMemo(
    69→    () => !Capacitor.isNativePlatform() && !!(
    70→      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition
    71→    ),
    72→    []
    73→  );
    74→  const [isRecording, setIsRecording] = useState(false);
    75→  const recognitionRef = useRef<any>(null);
    76→  const pendingVoiceRef = useRef<string>('');
    77→
    78→  const stopRecording = useCallback(() => {
    79→    if (recognitionRef.current) {
    80→      recognitionRef.current.stop();
    81→      recognitionRef.current = null;
    82→    }
    83→    setIsRecording(false);
    84→  }, []);
    85→
    86→  const startRecording = useCallback(() => {
    87→    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    88→    if (!SpeechRecognition) {
    89→      showToast('Speech recognition not supported in this browser', 'error');
    90→      return;
    91→    }
    92→
    93→    const recognition = new SpeechRecognition();
    94→    recognition.lang = 'en-IN';
    95→    recognition.interimResults = true;
    96→    recognition.continuous = false;
    97→
    98→    let finalTranscript = '';
    99→
   100→    recognition.onresult = (event: any) => {
   101→      let interim = '';
   102→      for (let i = event.resultIndex; i < event.results.length; i++) {
   103→        const transcript = event.results[i][0].transcript;
   104→        if (event.results[i].isFinal) {
   105→          finalTranscript += transcript;
   106→        } else {
   107→          interim += transcript;
   108→        }
   109→      }
   110→      setInput(finalTranscript + interim);
   111→    };
   112→
   113→    recognition.onend = () => {
   114→      setIsRecording(false);
   115→      recognitionRef.current = null;
   116→      // Auto-send directly with the captured transcript (avoids stale state from DOM click)
   117→      if (finalTranscript.trim()) {
   118→        pendingVoiceRef.current = finalTranscript.trim();
   119→        setTimeout(() => {
   120→          if (pendingVoiceRef.current) {
   121→            handleSendWithText(pendingVoiceRef.current);
   122→            pendingVoiceRef.current = '';
   123→          }
   124→        }, 100);
   125→      }
   126→    };
   127→
   128→    recognition.onerror = (event: any) => {
   129→      console.error('Speech error:', event.error);
   130→      setIsRecording(false);
   131→      recognitionRef.current = null;
   132→    };
   133→
   134→    recognitionRef.current = recognition;
   135→    recognition.start();
   136→    setIsRecording(true);
   137→    haptic.medium();
   138→  }, [showToast]);
   139→
   140→  const toggleRecording = useCallback(() => {
   141→    if (isRecording) stopRecording();
   142→    else startRecording();
   143→  }, [isRecording, stopRecording, startRecording]);
   144→
   145→  // Reset on open; stop recording on close
   146→  useEffect(() => {
   147→    if (isOpen) {
   148→      setMessages([{
   149→        id: 'welcome',
   150→        role: 'assistant',
   151→        content: 'Hi! I can help you add sales, purchases, payments, and more. Just describe what you need.',
   152→        timestamp: new Date()
   153→      }]);
   154→      setInput('');
   155→      setFile(null);
   156→      setPendingCount(OfflineQueueService.getPendingCount());
   157→    } else {
   158→      // Always stop microphone when modal closes
   159→      stopRecording();
   160→    }
   161→  }, [isOpen]);
   162→
   163→  // Scroll to bottom on new message
   164→  useEffect(() => {
   165→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   166→  }, [messages]);
   167→
   168→  // Online status listener
   169→  useEffect(() => {
   170→    const handleOnline = () => {
   171→      setIsOnline(true);
   172→      processOfflineQueue();
   173→    };
   174→    const handleOffline = () => setIsOnline(false);
   175→
   176→    window.addEventListener('online', handleOnline);
   177→    window.addEventListener('offline', handleOffline);
   178→    
   179→    return () => {
   180→      window.removeEventListener('online', handleOnline);
   181→      window.removeEventListener('offline', handleOffline);
   182→    };
   183→  }, []);
   184→
   185→  // Build context for AI
   186→  const buildContext = () => ({
   187→    customers: parties.filter(p => p.role === 'customer').map(p => p.name),
   188→    suppliers: parties.filter(p => p.role === 'supplier').map(p => p.name),
   189→    items: inventory.map(i => i.name),
   190→    expenseTypes: appSettings?.custom_lists?.expense_types || []
   191→  });
   192→
   193→  // Enrich entry with DB data
   194→  const enrichEntry = (entry: any) => {
   195→    const enriched = { ...entry };
   196→
   197→    // Party Details
   198→    if (enriched.party_name) {
   199→      const match = parties.find(p => (p.name || '').toLowerCase() === enriched.party_name.toLowerCase());
   200→      if (match) {
   201→        enriched.party_name = match.name;
   202→        enriched.gstin = match.gstin;
   203→        enriched.address = match.address;
   204→      }
   205→    }
   206→
   207→    // Inventory Details
   208→    if (enriched.items && Array.isArray(enriched.items)) {
   209→      enriched.items = enriched.items.map((item: any) => {
   210→        const match = inventory.find(i => (i.name || '').toLowerCase() === (item.item_name || '').toLowerCase());
   211→        if (match) {
   212→          const isSell = enriched.type === 'sell';
   213→          const dbRate = isSell ? match.sale_rate : match.purchase_rate;
   214→          
   215→          const newItem = {
   216→            ...item,
   217→            item_name: match.name,
   218→            hsn_code: match.hsn_code || '',
   219→            gst_percent: match.gst_percent || '',
   220→            unit: match.unit || 'Pcs',
   221→            price_type: match.price_type || 'exclusive',
   222→            rate: Number(item.rate) || Number(dbRate) || 0
   223→          };
   224→
   225→          const qty = Number(newItem.quantity) || 0;
   226→          const rate = Number(newItem.rate) || 0;
   227→          const gst = Number(newItem.gst_percent) || 0;
   228→          
   229→          if (newItem.price_type === 'inclusive') {
   230→            newItem.total = qty * rate;
   231→          } else {
   232→            newItem.total = (qty * rate) * (1 + gst / 100);
   233→          }
   234→          return newItem;
   235→        }
   236→        return item;
   237→      });
   238→
   239→      if (enriched.items.length > 0) {
   240→        enriched.total_amount = enriched.items.reduce((sum: number, i: any) => sum + (Number(i.total) || 0), 0);
   241→      }
   242→    }
   243→
   244→    return enriched;
   245→  };
   246→
   247→  const processOfflineQueue = async () => {
   248→    if (!isOnline) return;
   249→    
   250→    await OfflineQueueService.processQueue(
   251→      async (text, file) => GeminiService.processInput(text, file, buildContext()),
   252→      async (commands) => {
   253→        for (const cmd of commands) {
   254→          const { collection, ...data } = enrichEntry(cmd);
   255→          if (collection) {
   256→            await ApiService.add(user.uid, collection, { ...data, created_at: new Date().toISOString() });
   257→          }
   258→        }
   259→        invalidateAll(user.uid);
   260→      }
   261→    );
   262→    setPendingCount(OfflineQueueService.getPendingCount());
   263→  };
   264→
   265→  // Shared send logic that accepts an explicit text (for voice) or uses state input
   266→  const handleSendWithText = async (text: string, fileArg?: File | null) => {
   267→    const currentInput = text;
   268→    const currentFile = fileArg ?? null;
   269→    if (!currentInput.trim() && !currentFile) return;
   270→
   271→    const userMessage: Message = {
   272→      id: Date.now().toString(),
   273→      role: 'user',
   274→      content: currentFile ? `📎 ${currentFile.name}
   275→${currentInput}` : currentInput,
   276→      timestamp: new Date()
   277→    };
   278→    setMessages(prev => [...prev, userMessage]);
   279→    setInput('');
   280→    setFile(null);
   281→    setAiLoading(true);
   282→    haptic.medium();
   283→
   284→    if (!isOnline) {
   285→      await OfflineQueueService.enqueue(currentInput, currentFile || undefined);
   286→      setPendingCount(OfflineQueueService.getPendingCount());
   287→      setMessages(prev => [...prev, {
   288→        id: Date.now().toString(),
   289→        role: 'assistant',
   290→        content: "📴 You're offline. I've saved your command and will process it when you're back online.",
   291→        timestamp: new Date()
   292→      }]);
   293→      setAiLoading(false);
   294→      return;
   295→    }
   296→
   297→    try {
   298→      const commands = await GeminiService.processInput(currentInput, currentFile, buildContext());
   299→      if (!commands || commands.length === 0) {
   300→        setMessages(prev => [...prev, {
   301→          id: Date.now().toString(),
   302→          role: 'assistant',
   303→          content: `I couldn't understand that. Could you rephrase? For example: "Sold 50 cement bags to Rahul for 18000" or "Received 5000 from Suresh"`,
   304→          timestamp: new Date()
   305→        }]);
   306→      } else {
   307→        const enrichedCommands = commands.map((cmd: any) => enrichEntry(cmd));
   308→        const summary = enrichedCommands.map((cmd: any) => {
   309→          const type = cmd.collection?.replace('_', ' ') || 'entry';
   310→          const name = cmd.party_name || cmd.name || cmd.category || 'New';
   311→          const amount = cmd.total_amount || cmd.amount || '';
   312→          return `• ${type}: ${name}${amount ? ` (₹${amount})` : ''}`;
   313→        }).join('\n');               // ← use explicit newline
   314→        setMessages(prev => [...prev, {
   315→          id: Date.now().toString(),
   316→          role: 'assistant',
   317→          content: `I found ${enrichedCommands.length} entries:\n${summary}\nWould you like me to save these?`,
   318→          data: enrichedCommands,
   319→          timestamp: new Date()
   320→        }]);
   321→      }
   322→      haptic.success();
   323→    } catch (e: any) {
   324→      console.error(e);
   325→      haptic.error();
   326→      setMessages(prev => [...prev, {
   327→        id: Date.now().toString(),
   328→        role: 'assistant',
   329→        content: `❌ Error: ${e.message || 'Processing failed'}. Please try again.`,
   330→        timestamp: new Date()
   331→      }]);
   332→    } finally {
   333→      setAiLoading(false);
   334→    }
   335→  };
   336→
   337→  // handleSend delegates to handleSendWithText using current state values
   338→  const handleSend = async () => {
   339→    await handleSendWithText(input, file);
   340→  };
   341→
   342→  const handleSaveAll = async (msgId: string, data: any[]) => {
   343→    setSavingMsgIds(prev => new Set(prev).add(msgId));
   344→    const offline = !navigator.onLine;
   345→    try {
   346→      let count = 0;
   347→      for (const cmd of data) {
   348→        const { collection, _linkedPayments, ...rest } = cmd;
   349→        if (collection) {
   350→          const payload = { ...rest, created_at: new Date().toISOString() };
   351→          if (offline) {
   352→            SyncQueueService.addToQueue(user.uid, 'create', collection, payload);
   353→          } else {
   354→            await ApiService.add(user.uid, collection, payload);
   355→          }
   356→          count++;
   357→
   358→          // Save any linked payments that were added during manual editing
   359→          if (_linkedPayments && _linkedPayments.length > 0) {
   360→            const isSale = collection === 'ledger_entries' && rest.type === 'sell';
   361→            const txType = isSale ? 'received' : 'paid';
   362→            for (const pay of _linkedPayments) {
   363→              const transPayload = {
   364→                date: pay.date,
   365→                amount: Number(pay.amount) || 0,
   366→                payment_mode: pay.payment_mode || 'Cash',
   367→                payment_purpose: pay.payment_purpose || '',
   368→                party_name: pay.party_name || rest.party_name || '',
   369→                bill_no: pay.bill_no || rest.invoice_no || rest.bill_no || '',
   370→                notes: pay.notes || '',
   371→                type: txType,
   372→                transaction_id: getIDForEntry(txType),
   373→                created_at: new Date().toISOString()
   374→              };
   375→              if (offline) {
   376→                SyncQueueService.addToQueue(user.uid, 'create', 'transactions', transPayload);
   377→              } else {
   378→                await ApiService.add(user.uid, 'transactions', transPayload);
   379→              }
   380→              count++;
   381→            }
   382→          }
   383→        }
   384→      }
   385→      
   386→      invalidateAll(user.uid);
   387→      
   388→      const savedMsg = offline
   389→        ? `📴 Saved ${count} entries offline — will sync when online`
   390→        : `✅ Saved ${count} entries successfully! Need anything else?`;
   391→
   392→      setMessages(prev => [...prev, {
   393→        id: Date.now().toString(),
   394→        role: 'assistant',
   395→        content: savedMsg,
   396→        timestamp: new Date()
   397→      }]);
   398→      
   399→      haptic.success();
   400→      if (onSuccess) onSuccess();
   401→    } catch (e) {
   402→      console.error(e);
   403→      showToast("Save failed", "error");
   404→    } finally {
   405→      setSavingMsgIds(prev => { const s = new Set(prev); s.delete(msgId); return s; });
   406→    }
   407→  };
   408→
   409→  const handleEditItem = (item: any) => {
   410→    setEditData(item);
   411→    setShowEditModal(true);
   412→  };
   413→
   414→  const getModalType = (item: any) => {
   415→    if (!item) return 'sales';
   416→    if (item.collection === 'ledger_entries') return item.type === 'sell' ? 'sales' : 'purchases';
   417→    if (item.collection === 'transactions') return 'transactions';
   418→    if (item.collection === 'inventory') return 'inventory';
   419→    if (item.collection === 'expenses') return 'expenses';
   420→    if (item.collection === 'vehicles') return 'vehicles';
   421→    if (item.collection === 'parties') return 'parties';
   422→    return 'sales';
   423→  };
   424→
   425→  if (!isOpen) return null;
   426→
   427→  return (
   428→    <>
   429→      <div className="fixed inset-0 bg-black/80 z-50 flex items-end justify-center backdrop-blur-sm animate-in fade-in duration-200" style={{paddingBottom: 'env(safe-area-inset-bottom, 0px)'}}>
   430→        <div className="command-modal-root w-full max-w-2xl rounded-t-3xl overflow-hidden shadow-2xl border border-white/10 border-b-0 flex flex-col" style={{height: '90dvh', maxHeight: '90dvh', background: 'var(--app-bg)'}}>
   431→          
   432→          {/* Header */}
   433→          <div className="p-4 border-b border-white/08 flex justify-between items-center shrink-0">
   434→            <div className="flex items-center gap-2">
   435→              <div className="p-2 rounded-lg bg-[rgba(139,92,246,0.18)] text-violet-400">
   436→                <Sparkles size={18} />
   437→              </div>
   438→              <div>
   439→                <h2 className="font-bold text-lg ">AI Assistant</h2>
   440→                <div className="flex items-center gap-2">
   441→                  <span className={`w-2 h-2 rounded-full ${isOnline ? 'bg-green-500' : 'bg-red-500'}`} />
   442→                  <span className="text-xs text-slate-500">
   443→                    {isOnline ? 'Online' : 'Offline'}
   444→                    {pendingCount > 0 && ` • ${pendingCount} queued`}
   445→                  </span>
   446→                </div>
   447→              </div>
   448→            </div>
   449→            <div className="flex items-center gap-2">
   450→              {pendingCount > 0 && isOnline && (
   451→                <button 
   452→                  onClick={processOfflineQueue}
   453→                  className="p-2 bg-[rgba(59,130,246,0.15)] text-blue-400 rounded-lg"
   454→                >
   455→                  <RefreshCw size={18} />
   456→                </button>
   457→              )}
   458→              <button onClick={onClose} className="p-2 hover:bg-slate-200 hover:bg-[rgba(255,255,255,0.08)] rounded-full text-[rgba(240,244,255,0.95)]">
   459→                <X size={20}/>
   460→              </button>
   461→            </div>
   462→          </div>
   463→
   464→          {/* Messages */}
   465→          <div className="flex-1 overflow-y-auto p-4 space-y-4">
   466→            {messages.map((msg) => (
   467→              <div 
   468→                key={msg.id} 
   469→                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
   470→              >
   471→                <div className={`max-w-[85%] p-3 rounded-2xl ${
   472→                  msg.role === 'user' 
   473→                    ? 'bg-blue-600 text-white rounded-br-sm' 
   474→                    : 'border border-white/12 rounded-bl-sm'
   475→                }`}>
   476→                  <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
   477→                  
   478→                  {/* Action buttons for data */}
   479→                  {msg.data && msg.data.length > 0 && (
   480→                    <div className="mt-3 space-y-2">
   481→                      {msg.data.map((item: any, idx: number) => (
   482→                        <div 
   483→                          key={idx} 
   484→                          className="bg-[rgba(255,255,255,0.08)] p-2 rounded-lg flex items-center justify-between"
   485→                        >
   486→                          <span className="text-xs font-medium truncate flex-1 text-[rgba(203,213,225,0.8)]">
   487→                            {item.party_name || item.name || item.category || 'Entry'}
   488→                          </span>
   489→                          <button 
   490→                            onClick={() => handleEditItem(item)}
   491→                            className="p-1.5 text-violet-400 hover:bg-[rgba(139,92,246,0.15)] rounded"
   492→                          >
   493→                            <Edit2 size={14} />
   494→                          </button>
   495→                        </div>
   496→                      ))}
   497→                      <button
   498→                        onClick={() => handleSaveAll(msg.id, msg.data!)}
   499→                        disabled={savingMsgIds.has(msg.id)}
   500→                        className="w-full mt-2 bg-green-600 text-white py-2 rounded-xl text-sm font-bold flex items-center justify-center gap-2"
   501→                      >
   502→                        {savingMsgIds.has(msg.id) ? <Loader2 size={16} className="animate-spin" /> : <CheckCircle2 size={16} />}
   503→                        Save All
   504→                      </button>
   505→                    </div>
   506→                  )}
   507→                </div>
   508→              </div>
   509→            ))}
   510→            {aiLoading && (
   511→              <div className="flex justify-start">
   512→                <div className="p-3 rounded-2xl rounded-bl-sm border border-white/12">
   513→                  <Loader2 size={20} className="animate-spin text-slate-400" />
   514→                </div>
   515→              </div>
   516→            )}
   517→            <div ref={messagesEndRef} />
   518→          </div>
   519→
   520→          {/* Input */}
   521→          <div className="p-3 border-t border-white/08 shrink-0" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom, 0px) + 12px)' }}>
   522→            {!isOnline && (
   523→              <div className="mb-2 flex items-center gap-2 text-orange-600 text-xs font-medium">
   524→                <WifiOff size={14} />
   525→                Commands will be queued and processed when online
   526→              </div>
   527→            )}
   528→            
   529→            {file && (
   530→              <div className="mb-2 flex items-center gap-2 bg-[rgba(59,130,246,0.08)] p-2 rounded-lg">
   531→                <ImageIcon size={14} className="text-blue-600" />
   532→                <span className="text-xs text-[#93c5fd] flex-1 truncate">{file.name}</span>
   533→                <button onClick={() => setFile(null)} className="text-red-500">
   534→                  <X size={14} />
   535→                </button>
   536→              </div>
   537→            )}
   538→
   539→            {/* Input row — image | text | send + optional floating mic (web only) */}
   540→            <div className={`relative ${voiceSupported ? 'pt-10' : ''}`}>
   541→              {/* Floating mic button — only shown on web where Speech API is available */}
   542→              {voiceSupported && (
   543→                <button
